import reflex as rx

class EstadoContador(rx.State):
    valor: int = 0
    def incrementar(self):
        self.valor += 1

def index():
    # Interfaz definida con componentes de Python
    return rx.vstack(
        rx.heading(f'Valor actual: {EstadoContador.valor}', size='8'),
        rx.button('Incrementar', on_click=EstadoContador.incrementar),
        padding='2em'
    )

app = rx.App()
app.add_page(index)

import typer

app = typer.Typer()

@app.command()
def saludar(nombre: str, formal: bool = False):
    # El tipo de 'nombre' y el valor por defecto de 'formal' crean el CLI
    if formal:
        typer.echo(f'Buenos días, Licenciado {nombre}.')
    else:
        typer.echo(f'¡Hola {nombre}!')

if __name__ == '__main__':
    app()
